package com.example.oauthprovider.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
@EnableWebSecurity
public class WebSecurityConfig {

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .csrf(csrf -> csrf.disable()) // Disable CSRF for API endpoints, in a real app, configure appropriately
            .authorizeHttpRequests(authorize -> authorize
                .requestMatchers("/oauth/**").permitAll() // Allow unauthenticated access to OAuth endpoints for this example
                .anyRequest().authenticated() // All other requests require authentication
            )
            .formLogin(form -> form.disable()); // Disable form login for this example to not interfere with OAuth flow
        return http.build();
    }
}

