package com.example.oauthprovider.service;

import com.example.oauthprovider.model.AccessToken;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class AccessTokenService {
    // In-memory storage for access tokens
    private final Map<String, AccessToken> accessTokens = new ConcurrentHashMap<>();
    public static final long TOKEN_EXPIRATION_SECONDS = 60 * 60; // 1 hour

    public AccessToken createAccessToken(String clientId, String userId, String scope) {
        AccessToken token = new AccessToken(clientId, userId, scope, TOKEN_EXPIRATION_SECONDS);
        accessTokens.put(token.getToken(), token);
        return token;
    }

    public AccessToken findAccessToken(String token) {
        AccessToken accessToken = accessTokens.get(token);
        if (accessToken != null && accessToken.isExpired()) {
            accessTokens.remove(token); // Clean up expired token
            return null;
        }
        return accessToken;
    }
}

