package com.example.oauthprovider.service;

import com.example.oauthprovider.model.AuthorizationCode;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class AuthorizationCodeService {
    // In-memory storage for authorization codes
    private final Map<String, AuthorizationCode> authorizationCodes = new ConcurrentHashMap<>();
    private static final long CODE_EXPIRATION_SECONDS = 10 * 60; // 10 minutes

    public AuthorizationCode createAuthorizationCode(String clientId, String redirectUri, String scope, String userId) {
        AuthorizationCode code = new AuthorizationCode(clientId, redirectUri, scope, userId, CODE_EXPIRATION_SECONDS);
        authorizationCodes.put(code.getCode(), code);
        return code;
    }

    public AuthorizationCode validateAuthorizationCode(String code, String clientId, String redirectUri) {
        AuthorizationCode authCode = authorizationCodes.get(code);

        if (authCode == null || authCode.isExpired()) {
            return null; // Code not found or expired
        }

        // Validate client_id and redirect_uri match the ones stored with the code
        if (!authCode.getClientId().equals(clientId) || !authCode.getRedirectUri().equals(redirectUri)) {
            return null; // Mismatch
        }

        return authCode;
    }

    public void removeAuthorizationCode(String code) {
        authorizationCodes.remove(code);
    }
}

