package com.example.oauthprovider.controller;

import com.example.oauthprovider.model.AccessToken;
import com.example.oauthprovider.model.AuthorizationCode;
import com.example.oauthprovider.model.Client;
import com.example.oauthprovider.service.AccessTokenService;
import com.example.oauthprovider.service.AuthorizationCodeService;
import com.example.oauthprovider.service.ClientService;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.util.UriComponentsBuilder;

import java.io.IOException;
import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/oauth")
public class OAuthController {

    @Autowired
    private ClientService clientService;
    @Autowired
    private AuthorizationCodeService authorizationCodeService;
    @Autowired
    private AccessTokenService accessTokenService;

    // The /oauth/authorize endpoint handles client authorization requests.
    // In a real application, a user would be authenticated and presented with a consent screen here.
    // For this example, we assume consent is implicitly granted by a dummy user.
    @GetMapping("/authorize")
    public void authorize(
            @RequestParam("response_type") String responseType,
            @RequestParam("client_id") String clientId,
            @RequestParam("redirect_uri") String redirectUri,
            @RequestParam(value = "scope", required = false) String scope,
            @RequestParam(value = "state", required = false) String state,
            HttpServletResponse httpResponse) throws IOException {

        // 1. Validate response_type (must be 'code' for Authorization Code Flow)
        if (!"code".equals(responseType)) {
            sendErrorResponse(httpResponse, redirectUri, "unsupported_response_type", state, "Only 'code' response type is supported.");
            return;
        }

        // 2. Validate client_id
        Client client = clientService.findClientById(clientId);
        if (client == null) {
            // If client_id is invalid, redirect_uri can't be trusted. A real server might display an error page.
            // For this example, we'll try to redirect if redirect_uri is provided, or throw if not.
            sendErrorResponse(httpResponse, redirectUri, "unauthorized_client", state, "Client not found.");
            return;
        }

        // 3. Validate redirect_uri based on registered client's base URL
        // The redirect_uri must start with the client's registered baseRedirectUri to allow dynamic subdomains and paths.
        if (!redirectUri.startsWith(client.getBaseRedirectUri())) {
            // According to spec, if redirect_uri is invalid, server SHOULD NOT redirect.
            // For this example, we are redirecting as a simplification.
            sendErrorResponse(httpResponse, redirectUri, "invalid_redirect_uri", state, "Redirect URI does not match registered base URI.");
            return;
        }

        // 4. User authentication/consent (simplified for this example)
        // In a real application, the user would be authenticated and asked for consent.
        // We simulate a user "user123" granting consent.
        String userId = "user123";

        // 5. Generate authorization code
        AuthorizationCode authCode = authorizationCodeService.createAuthorizationCode(clientId, redirectUri, scope, userId);

        // 6. Redirect to client's redirect_uri with the generated code and original state
        UriComponentsBuilder uriBuilder = UriComponentsBuilder.fromUriString(redirectUri)
                .queryParam("code", authCode.getCode());

        if (state != null && !state.isEmpty()) {
            uriBuilder.queryParam("state", state);
        }

        httpResponse.sendRedirect(uriBuilder.toUriString());
    }

    // The /oauth/token endpoint handles token exchange for authorization codes.
    @PostMapping("/token")
    public ResponseEntity<?> token(
            @RequestParam("grant_type") String grantType,
            @RequestParam("code") String code,
            @RequestParam("redirect_uri") String redirectUri,
            @RequestParam("client_id") String clientId,
            @RequestParam("client_secret") String clientSecret) {

        // 1. Validate grant_type (must be 'authorization_code')
        if (!"authorization_code".equals(grantType)) {
            return ResponseEntity.badRequest().body(createErrorResponse("unsupported_grant_type", "Only 'authorization_code' grant type is supported."));
        }

        // 2. Authenticate client (using client_id and client_secret)
        if (!clientService.validateClient(clientId, clientSecret)) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body(createErrorResponse("invalid_client", "Invalid client_id or client_secret."));
        }

        // 3. Validate authorization code
        // It checks existence, expiration, and matches client_id and redirect_uri
        AuthorizationCode authCode = authorizationCodeService.validateAuthorizationCode(code, clientId, redirectUri);
        if (authCode == null) {
            return ResponseEntity.badRequest().body(createErrorResponse("invalid_grant", "Invalid or expired authorization code, or mismatching redirect_uri/client_id."));
        }

        // 4. Consume the authorization code (one-time use)
        authorizationCodeService.removeAuthorizationCode(code);

        // 5. Generate access token
        AccessToken accessToken = accessTokenService.createAccessToken(
                authCode.getClientId(),
                authCode.getUserId(),
                authCode.getScope());

        // 6. Return access token response in JSON format
        Map<String, Object> tokenResponse = new HashMap<>();
        tokenResponse.put("access_token", accessToken.getToken());
        tokenResponse.put("token_type", "Bearer");
        tokenResponse.put("expires_in", AccessTokenService.TOKEN_EXPIRATION_SECONDS);
        if (accessToken.getScope() != null && !accessToken.getScope().isEmpty()) {
            tokenResponse.put("scope", accessToken.getScope());
        }

        return ResponseEntity.ok(tokenResponse);
    }

    // Helper method to construct and send an error redirect to the client.
    private void sendErrorResponse(HttpServletResponse httpResponse, String redirectUri,
                                   String error, String state, String errorDescription) throws IOException {
        UriComponentsBuilder uriBuilder = UriComponentsBuilder.fromUriString(redirectUri)
                .queryParam("error", error)
                .queryParam("error_description", errorDescription);

        if (state != null && !state.isEmpty()) {
            uriBuilder.queryParam("state", state);
        }

        httpResponse.sendRedirect(uriBuilder.toUriString());
    }

    // Helper method to create an error response for the token endpoint.
    private Map<String, String> createErrorResponse(String error, String errorDescription) {
        Map<String, String> errorResponse = new HashMap<>();
        errorResponse.put("error", error);
        errorResponse.put("error_description", errorDescription);
        return errorResponse;
    }
}